class Leaky {
    int* data1;
    int* data2;
public:
    Leaky() {
        data1 = new int[100];  // ❌ If next line throws, data1 leaks
        data2 = new int[200];  // This might throw (bad_alloc)
    }
    ~Leaky() {
        delete[] data1;  // Never called if constructor throws
        delete[] data2;
    }
};

