        // Wait if buffer is empty
        cv_not_empty.wait(lock, []{ return !buffer.empty(); });

        int value = buffer.front();
        buffer.pop();
        std::cout << "Consumer " << id << " consumed " << value
                  << " (buffer size: " << buffer.size() << ")\n";

        cv_not_full.notify_one();  // Wake producer
    }
}

