#include <atomic>
#include <iostream>

template<typename T>
struct Node {
    T value;
    Node* next;
    Node(T val) : value(val), next(nullptr) {}
};

template<typename T>
class LockFreeStack {
private:
    std::atomic<Node<T>*> head;

public:
    LockFreeStack() : head(nullptr) {}

    void push(T value) {
        Node<T>* new_node = new Node<T>(value);
        new_node->next = head.load();  // Load current head

        // CAS loop: retry until successful
        while (!head.compare_exchange_weak(new_node->next, new_node)) {
            // On failure, new_node->next is updated with current head
        }
    }

    bool pop(T& result) {
        Node<T>* old_head = head.load();

        while (old_head && !head.compare_exchange_weak(old_head, old_head->next)) {
            // On failure, old_head updated with current head, retry
        }

        if (old_head) {
            result = old_head->value;
            delete old_head;  // ⚠️ Unsafe: see memory reclamation edge case
            return true;
        }
        return false;
    }
};

int main() {
    LockFreeStack<int> stack;
    stack.push(10);
    stack.push(20);
    stack.push(30);

    int val;
    while (stack.pop(val)) {
        std::cout << val << "\n";
    }
    return 0;
}

