        sensor_readings.insert(sensor_readings.end(),
                              local_buffer.begin(),
                              local_buffer.end());
    };

    std::thread t1(writer, 1);
    std::thread t2(writer, 2);

    t1.join();
    t2.join();

    std::cout << "Vector size: " << sensor_readings.size() << "\n";
}

