    // LiDAR thread: 10 Hz
    std::thread lidar([&]() {
        for (int i = 0; i < 10; ++i) {
            SensorReading reading{
                2,  // lidar sensor_id
                static_cast<double>(i * 10),
                std::chrono::system_clock::now()
            };
            aggregator.add_reading(reading);
            std::this_thread::sleep_for(std::chrono::milliseconds(100));  // 10 Hz
        }
    });

