        for (int i = 0; i < 20; ++i) {
            SensorReading reading{
                3,  // radar sensor_id
                static_cast<double>(i * 5),
                std::chrono::system_clock::now()
            };
            aggregator.add_reading(reading);
            std::this_thread::sleep_for(std::chrono::milliseconds(50));  // 20 Hz
        }
    });

    camera.join();
    lidar.join();
    radar.join();

    aggregator.print_summary();

