    ILogger& operator=(const ILogger&) = delete;
};

class FileLogger : public ILogger {
    std::ofstream file;
public:
    explicit FileLogger(const std::string& filename) {
        file.open(filename, std::ios::app);
    }

    void log(const std::string& message) override {
