#include <iostream>
#include <cstring>

class Buffer {
    char* data;
    size_t size;

public:
    // Constructor
    Buffer(size_t s) : size(s) {
        data = new char[size];
        std::cout << "Constructed Buffer of size " << size << "\n";
    }

    // Destructor
    ~Buffer() {
        delete[] data;
        std::cout << "Destroyed Buffer\n";
    }

    // Copy constructor (deep copy)
    Buffer(const Buffer& other) : size(other.size) {
        data = new char[size];
        std::memcpy(data, other.data, size);
        std::cout << "Copy constructed Buffer\n";
    }

    // Move constructor (transfer ownership)
    Buffer(Buffer&& other) noexcept 
        : data(other.data), size(other.size) {
        other.data = nullptr;  // ✅ Prevent double-delete
        other.size = 0;
        std::cout << "Move constructed Buffer\n";
    }
};

int main() {
    Buffer b1(100);
    Buffer b2 = std::move(b1);  // Move constructor called
    // b1 is now in valid but unspecified state (data=nullptr, size=0)
}

#include <iostream>
#include <algorithm>

class DynamicArray {
    int* data;
    size_t size;

public:
    DynamicArray(size_t s) : size(s), data(new int[s]) { }

    ~DynamicArray() { delete[] data; }

    // Copy assignment
    DynamicArray& operator=(const DynamicArray& other) {
        if (this != &other) {
            delete[] data;
            size = other.size;
            data = new int[size];
            std::copy(other.data, other.data + size, data);
            std::cout << "Copy assigned\n";
        }
        return *this;
    }

    // Move assignment
    DynamicArray& operator=(DynamicArray&& other) noexcept {
        if (this != &other) {  // ✅ Check self-assignment
            delete[] data;      // Clean up existing resource

            data = other.data;  // Steal resource
            size = other.size;

            other.data = nullptr;  // Nullify source
            other.size = 0;
            std::cout << "Move assigned\n";
        }
        return *this;
    }
};

int main() {
    DynamicArray arr1(10);
    DynamicArray arr2(20);

    arr2 = std::move(arr1);  // Move assignment
    // arr1 is now empty but valid
}

#include <iostream>
#include <string>

class Resource {
    std::string name;
    int* data;
    size_t size;

public:
    // 1. Constructor
    Resource(const std::string& n, size_t s) 
        : name(n), size(s), data(new int[s]) {
        std::cout << "Constructed " << name << "\n";
    }

    // 2. Destructor
    ~Resource() {
        delete[] data;
        std::cout << "Destroyed " << name << "\n";
    }

    // 3. Copy constructor
    Resource(const Resource& other)
        : name(other.name + "_copy"), size(other.size), 
          data(new int[other.size]) {
        std::copy(other.data, other.data + size, data);
        std::cout << "Copy constructed " << name << "\n";
    }

    // 4. Copy assignment
    Resource& operator=(const Resource& other) {
        if (this != &other) {
            delete[] data;
            name = other.name + "_assigned";
            size = other.size;
            data = new int[size];
            std::copy(other.data, other.data + size, data);
            std::cout << "Copy assigned " << name << "\n";
        }
        return *this;
    }

    // 5. Move constructor
    Resource(Resource&& other) noexcept
        : name(std::move(other.name)), size(other.size), 
          data(other.data) {
        other.data = nullptr;
        other.size = 0;
        std::cout << "Move constructed " << name << "\n";
    }

    // 6. Move assignment
    Resource& operator=(Resource&& other) noexcept {
        if (this != &other) {
            delete[] data;
            name = std::move(other.name);
            size = other.size;
            data = other.data;
            other.data = nullptr;
            other.size = 0;
            std::cout << "Move assigned " << name << "\n";
        }
        return *this;
    }
};

