class LRUCache {
    std::list<std::pair<int, int>> items;
    std::unordered_map<int, decltype(items)::iterator> cache;
    size_t capacity;

public:
    int get(int key) {
        if (cache.find(key) == cache.end()) return -1;
        items.splice(items.begin(), items, cache[key]);
        return cache[key]->second;
    }
};

