template<typename T>
class Queue {
    std::deque<T> data;

public:
    void enqueue(const T& value) {
        data.push_back(value);  // O(1)
    }

    T dequeue() {
        T value = data.front();
        data.pop_front();  // O(1)
        return value;
    }

    const T& front() const {
        return data.front();
    }

    bool empty() const {
        return data.empty();
    }

    size_t size() const {
        return data.size();
    }
};

int main() {
