template<typename T>
class Stack {
    std::deque<T> data;
public:
    void push(const T& value) {
        data.push_back(value);  // O(1)
    }

    T pop() {
        T value = data.back();
        data.pop_back();  // O(1)
        return value;
    }

    const T& top() const {
        return data.back();  // O(1)
    }

    bool empty() const {
        return data.empty();
    }
};

