    for (int x : s) {
        std::cout << x << " ";  // Prints: 1 2 3 4 5 6 9
    }
    std::cout << "\n";

    // Membership test
    if (s.find(4) != s.end()) {
        std::cout << "4 is present\n";
    }

    // Erase by value
    s.erase(3);  // Removes element 3

    // Count occurrences (always 0 or 1 for set)
    std::cout << "Count of 5: " << s.count(5) << "\n";  // Prints: 1
}

